DROP TABLE IF EXISTS `bitacora_historico`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `bitacora_historico` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `bitacora_id` int(10) unsigned NOT NULL COMMENT 'ID original en tabla bitacora',
  `usuario_id` int(10) unsigned DEFAULT NULL,
  `accion` varchar(100) NOT NULL,
  `tabla_afectada` varchar(100) DEFAULT NULL,
  `registro_id` int(10) unsigned DEFAULT NULL,
  `ip_address` varchar(45) NOT NULL DEFAULT '',
  `user_agent` text DEFAULT NULL,
  `detalles` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`detalles`)),
  `created_at` datetime NOT NULL COMMENT 'Timestamp original del evento',
  `archivado_at` datetime NOT NULL DEFAULT current_timestamp() COMMENT 'Cuando fue archivado',
  PRIMARY KEY (`id`),
  KEY `idx_bitacora_id` (`bitacora_id`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_archivado_at` (`archivado_at`),
  KEY `idx_accion` (`accion`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Registros de bit??cora archivados (almac??n fr??o ??? s??lo lectura)';
